// src/hooks/solana/useSolanaWalletCluster.ts
import { useConnection } from '@/hooks/solana/useConnection'

export function useSolanaWalletCluster(): "devnet" | "mainnet-beta" | "testnet" | "unknown" {
  const connection = useConnection()
  const url = connection.rpcEndpoint

  if (url.includes('devnet')) return 'devnet'
  if (url.includes('mainnet')) return 'mainnet-beta'
  if (url.includes('testnet')) return 'testnet'
  return 'unknown'
}
